import{_ as n,c as a,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"インストール：5分で始める | opencode-dcp","description":"DCPプラグインのインストール方法を学びます。5分で設定を完了し、自動的なトリミングで長い会話のToken消費を大幅に削減し、AI応答の品質を向上させます。","frontmatter":{"title":"インストール：5分で始める | opencode-dcp","sidebarTitle":"5分で始める","subtitle":"インストール：5分で始める","description":"DCPプラグインのインストール方法を学びます。5分で設定を完了し、自動的なトリミングで長い会話のToken消費を大幅に削減し、AI応答の品質を向上させます。","tags":["インストール","クイックスタート","DCP"],"prerequisite":["OpenCodeがインストール済み"],"order":1},"headers":[],"relativePath":"ja/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md","filePath":"ja/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"}'),t={name:"ja/Opencode-DCP/opencode-dynamic-context-pruning/start/getting-started/index.md"};function i(l,s,p,d,c,r){return e(),a("div",null,[...s[0]||(s[0]=[o(`<h1 id="インストールとクイックスタート" tabindex="-1">インストールとクイックスタート <a class="header-anchor" href="#インストールとクイックスタート" aria-label="Permalink to &quot;インストールとクイックスタート&quot;">​</a></h1><h2 id="このチュートリアルでできること" tabindex="-1">このチュートリアルでできること <a class="header-anchor" href="#このチュートリアルでできること" aria-label="Permalink to &quot;このチュートリアルでできること&quot;">​</a></h2><ul><li>✅ 5分以内にDCPプラグインをインストール</li><li>✅ プラグインを設定し、インストールを検証</li><li>✅ 初回の自動トリミング効果を確認</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>OpenCodeを長期間使用すると、会話がどんどん長くなります：</p><ul><li>AIが同じファイルを何度も読み取る</li><li>ツール呼び出しのエラーメッセージがコンテキストを埋め尽くす</li><li>各会話で大量のTokenを消費する</li><li><strong>会話が長くなるほど、AIの応答が遅くなる</strong></li></ul><p>会話内の重複したコンテンツを自動的にクリーンアップしたいが、手動操作はしたくない。</p><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>**DCP（Dynamic Context Pruning）**はOpenCodeのプラグインで、会話履歴から重複したツール呼び出しを自動的に削除し、Token消費を削減します。</p><p>その動作：</p><ol><li><strong>自動検出</strong>：メッセージ送信ごとに会話履歴を自動的に分析</li><li><strong>スマートクリーンアップ</strong>：重複したツール呼び出し、期限切れのエラー、上書きされた書き込みを削除</li><li><strong>AI駆動</strong>：AIは<code>discard</code>および<code>extract</code>ツールを呼び出してコンテキストを最適化</li><li><strong>透明で制御可能</strong>：<code>/dcp</code>コマンドでトリミング統計を表示し、手動でクリーンアップを実行</li></ol><div class="tip custom-block"><p class="custom-block-title">核心メリット</p><ul><li><strong>ゼロコスト</strong>：自動戦略はLLM呼び出しを必要としません</li><li><strong>ゼロ設定</strong>：インストールするだけ、デフォルト設定はすでに最適化済み</li><li><strong>ゼロリスク</strong>：LLMに送信されるコンテキストのみを変更し、会話履歴には影響しません</li></ul></div><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><p>インストールを開始する前に、確認してください：</p><ul><li>[ ] <strong>OpenCode</strong>がインストール済み（プラグイン機能をサポート）</li><li>[ ] <strong>OpenCode設定ファイル</strong>を編集する方法を知っている</li><li>[ ] 基本的な<strong>JSONC構文</strong>を理解している（コメントをサポートするJSON）</li></ul><div class="warning custom-block"><p class="custom-block-title">重要なヒント</p><p>DCPはLLMに送信されるコンテキストの内容を変更しますが、会話履歴には影響しません。設定でいつでもプラグインを無効にできます。</p></div><h2 id="進め方" tabindex="-1">進め方 <a class="header-anchor" href="#進め方" aria-label="Permalink to &quot;進め方&quot;">​</a></h2><h3 id="ステップ1-opencode設定ファイルを編集" tabindex="-1">ステップ1：OpenCode設定ファイルを編集 <a class="header-anchor" href="#ステップ1-opencode設定ファイルを編集" aria-label="Permalink to &quot;ステップ1：OpenCode設定ファイルを編集&quot;">​</a></h3><p><strong>理由</strong> OpenCode設定でDCPプラグインを宣言すると、OpenCodeの起動時に自動的に読み込まれます。</p><p>OpenCode設定ファイル<code>opencode.jsonc</code>を開き、<code>plugin</code>フィールドにDCPを追加：</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// opencode.jsonc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@tarquinen/opencode-dcp@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>期待される結果</strong>：設定ファイルに他のプラグインがすでにある場合（もしあれば）、配列の末尾にDCPを追加するだけです。</p><div class="info custom-block"><p class="custom-block-title">ヒント</p><p><code>@latest</code>タグを使用すると、OpenCodeは起動時に最新バージョンを自動的に確認して取得します。</p></div><h3 id="ステップ2-opencodeを再起動" tabindex="-1">ステップ2：OpenCodeを再起動 <a class="header-anchor" href="#ステップ2-opencodeを再起動" aria-label="Permalink to &quot;ステップ2：OpenCodeを再起動&quot;">​</a></h3><p><strong>理由</strong> プラグイン設定の変更後、有効にするには再起動が必要です。</p><p>OpenCodeを完全に閉じて、再起動してください。</p><p><strong>期待される結果</strong>：OpenCodeが正常に起動し、エラーメッセージが表示されません。</p><h3 id="ステップ3-プラグインインストールを確認" tabindex="-1">ステップ3：プラグインインストールを確認 <a class="header-anchor" href="#ステップ3-プラグインインストールを確認" aria-label="Permalink to &quot;ステップ3：プラグインインストールを確認&quot;">​</a></h3><p><strong>理由</strong> DCPプラグインが正しく読み込まれていることを確認し、デフォルト設定を確認します。</p><p>OpenCodeの会話で入力：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dcp</span></span></code></pre></div><p><strong>期待される結果</strong>：DCPコマンドヘルプが表示され、プラグインが正常にインストールされたことがわかります。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><h3 id="ステップ4-デフォルト設定を確認" tabindex="-1">ステップ4：デフォルト設定を確認 <a class="header-anchor" href="#ステップ4-デフォルト設定を確認" aria-label="Permalink to &quot;ステップ4：デフォルト設定を確認&quot;">​</a></h3><p><strong>理由</strong> DCPのデフォルト設定を理解し、プラグインが期待通りに動作していることを確認します。</p><p>DCPは初回実行時に自動的に設定ファイルを作成します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># グローバル設定ファイルを表示</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/dcp.jsonc</span></span></code></pre></div><p><strong>期待される結果</strong>：設定ファイルが作成され、初期状態では<code>$schema</code>フィールドのみ含みます：</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://raw.githubusercontent.com/Opencode-DCP/opencode-dynamic-context-pruning/master/dcp.schema.json&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>設定ファイルは初期状態で<code>$schema</code>フィールドのみを含み、その他のすべての設定項目はコード内のデフォルト値を使用します。手動で設定する必要なく使用できます。</p><div class="tip custom-block"><p class="custom-block-title">デフォルト設定の説明</p><p>DCPのコードデフォルト値は以下の通りです（設定ファイルに書き込む必要はありません）：</p><ul><li><strong>deduplication</strong>：自動重複排除、重複したツール呼び出しを削除</li><li><strong>purgeErrors</strong>：4ターン前のエラーツール入力を自動的にクリーンアップ</li><li><strong>discard/extract</strong>：AIが呼び出せるトリミングツール</li><li><strong>pruneNotification</strong>：詳細なトリミング通知を表示</li></ul><p>カスタム設定が必要な場合は、これらのフィールドを手動で追加できます。詳細な設定説明は<a href="./../configuration/">設定ガイド</a>を参照してください。</p></div><h3 id="ステップ5-自動トリミング効果を体験" tabindex="-1">ステップ5：自動トリミング効果を体験 <a class="header-anchor" href="#ステップ5-自動トリミング効果を体験" aria-label="Permalink to &quot;ステップ5：自動トリミング効果を体験&quot;">​</a></h3><p><strong>理由</strong> 実際にDCPを使用し、自動トリミングの効果を確認します。</p><p>OpenCodeで会話を行い、AIに同じファイルを複数回読み取らせたり、失敗するツール呼び出しを実行したりします。</p><p><strong>期待される結果</strong>：</p><ol><li>メッセージを送信するたびに、DCPは会話履歴を自動的に分析</li><li>重複したツール呼び出しがある場合、DCPは自動的にクリーンアップ</li><li>AI応答後、トリミング通知が表示される場合があります（<code>pruneNotification</code>設定によります）</li></ol><p>トリミング通知の例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>▣ DCP | ~12.5K tokens saved total</span></span>
<span class="line"><span></span></span>
<span class="line"><span>▣ Pruning (~12.5K tokens)</span></span>
<span class="line"><span>→ read: src/config.ts</span></span>
<span class="line"><span>→ write: package.json</span></span></code></pre></div><p><code>/dcp context</code>を入力して現在のセッションのToken使用状況を確認：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>──────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>──────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>上記のステップを完了すると、次のことができるはずです：</p><ul><li>[ ] <code>opencode.jsonc</code>にDCPプラグインが追加済み</li><li>[ ] OpenCode再起動後、正常に実行できる</li><li>[ ] <code>/dcp</code>コマンドでヘルプが表示される</li><li>[ ] 設定ファイル<code>~/.config/opencode/dcp.jsonc</code>が作成済み</li><li>[ ] 会話でトリミング通知が見える、または<code>/dcp context</code>でトリミング統計が見える</li></ul><p><strong>あるステップで失敗した場合</strong>：</p><ul><li><code>opencode.jsonc</code>の構文が正しいか確認（JSONC形式）</li><li>OpenCodeログでプラグイン読み込みエラーがないか確認</li><li>OpenCodeバージョンがプラグイン機能をサポートしているか確認</li></ul><h2 id="落とし穴のヒント" tabindex="-1">落とし穴のヒント <a class="header-anchor" href="#落とし穴のヒント" aria-label="Permalink to &quot;落とし穴のヒント&quot;">​</a></h2><h3 id="問題1-プラグインが有効にならない" tabindex="-1">問題1：プラグインが有効にならない <a class="header-anchor" href="#問題1-プラグインが有効にならない" aria-label="Permalink to &quot;問題1：プラグインが有効にならない&quot;">​</a></h3><p><strong>症状</strong>：設定は追加したが、トリミング効果が見えない</p><p><strong>原因</strong>：OpenCodeが再起動されていないか、設定ファイルのパスが間違っている</p><p><strong>解決策</strong>：</p><ol><li>OpenCodeを完全に閉じてから再起動</li><li><code>opencode.jsonc</code>の位置が正しいか確認</li><li>ログを確認：<code>~/.config/opencode/logs/dcp/daily/</code>ディレクトリのログファイル</li></ol><h3 id="問題2-設定ファイルが作成されない" tabindex="-1">問題2：設定ファイルが作成されない <a class="header-anchor" href="#問題2-設定ファイルが作成されない" aria-label="Permalink to &quot;問題2：設定ファイルが作成されない&quot;">​</a></h3><p><strong>症状</strong>：<code>~/.config/opencode/dcp.jsonc</code>が存在しない</p><p><strong>原因</strong>：OpenCodeがDCPプラグインを呼び出していないか、設定ディレクトリの権限の問題</p><p><strong>解決策</strong>：</p><ol><li>OpenCodeが再起動済みであることを確認</li><li>設定ディレクトリを手動で作成：<code>mkdir -p ~/.config/opencode</code></li><li><code>opencode.jsonc</code>でプラグイン名が正しいか確認：<code>@tarquinen/opencode-dcp@latest</code></li></ol><h3 id="問題3-トリミング通知が表示されない" tabindex="-1">問題3：トリミング通知が表示されない <a class="header-anchor" href="#問題3-トリミング通知が表示されない" aria-label="Permalink to &quot;問題3：トリミング通知が表示されない&quot;">​</a></h3><p><strong>症状</strong>：トリミング通知が見えないが、<code>/dcp stats</code>にはトリミングが表示される</p><p><strong>原因</strong>：<code>pruneNotification</code>が<code>&quot;off&quot;</code>または<code>&quot;minimal&quot;</code>に設定されている</p><p><strong>解決策</strong>：設定ファイルを変更：</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pruneNotification&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;detailed&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // または &quot;minimal&quot;</span></span></code></pre></div><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>DCPプラグインのインストールは非常に簡単です：</p><ol><li><code>opencode.jsonc</code>にプラグインを追加</li><li>OpenCodeを再起動</li><li><code>/dcp</code>コマンドでインストールを確認</li><li>デフォルト設定で使用可能、追加の調整は不要</li></ol><p><strong>DCPでデフォルトで有効な機能</strong>：</p><ul><li>✅ 自動重複排除戦略（重複したツール呼び出しを削除）</li><li>✅ エラー削除戦略（期限切れのエラー入力をクリーンアップ）</li><li>✅ AI駆動ツール（<code>discard</code>と<code>extract</code>）</li><li>✅ 詳細なトリミング通知</li></ul><p><strong>次のステップ</strong>：設定をカスタマイズする方法を学び、トリミング戦略を調整してさまざまなシナリオのニーズに対応します。</p><hr><h2 id="次のチュートリアルの予告" tabindex="-1">次のチュートリアルの予告 <a class="header-anchor" href="#次のチュートリアルの予告" aria-label="Permalink to &quot;次のチュートリアルの予告&quot;">​</a></h2><blockquote><p>次のチュートリアルでは**<a href="./../configuration/">設定ガイド</a>**を学びます</p><p>学習内容：</p><ul><li>多階層設定システム（グローバル、環境変数、プロジェクトレベル）</li><li>すべての設定項目の目的と推奨設定</li><li>ターン保護、保護されたツール、保護されたファイルパターン</li><li>さまざまなトリミング戦略を有効化/無効化する方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行号</th></tr></thead><tbody><tr><td>プラグインエントリポイント</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/index.ts" target="_blank" rel="noreferrer"><code>index.ts</code></a></td><td>12-102</td></tr><tr><td>設定管理</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>669-794</td></tr><tr><td>コマンド処理</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>1-40</td></tr><tr><td>Token 計算</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>68-174</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>MAX_TOOL_CACHE_SIZE = 1000</code>：ツールキャッシュの最大エントリ数</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>Plugin()</code>：プラグイン登録とフック設定</li><li><code>getConfig()</code>：多階層設定の読み込みとマージ</li><li><code>handleContextCommand()</code>：現在のセッションのToken使用状況を分析</li></ul></details>`,83)])])}const u=n(t,[["render",i]]);export{g as __pageData,u as default};
